80 students each record the name of their mathematics teacher.
The number of these students taught by Mr House and by Miss Patel are shown in the bar chart.

%\begin{InsertScreenShot}
%    \relincludegraphics{Figures/Q02-BarChart.png}
%\end{InsertScreenShot}

\begin{parts}
\item How many more students are taught by Miss Patel than by Mr House?

\AnswerLine[][]
\Marks{1}

\item 15 students are taught by Mr Smith.
      Twice as many students are taught by Mrs Brown than by Mr Jones.

      Use this information to complete the bar chart.

\Answerspace[4cm]
\Marks{4}

\item Write down the mode.

\AnswerLine[][]
\Marks{1}

\item One of these students is chosen at random.

      Work out the probability that this student

      \begin{subparts}
      \item is taught by Mr House,

      \AnswerLine[][]
      \Marks{1}

      \item is not taught by either Mr House or Miss Patel.

      \AnswerLine[][]
      \Marks{2}
      \end{subparts}

\item This information is also to be shown in a pie chart.

      Work out the sector angle for Miss Patel.

\AnswerLine[][]
\Marks{2}
\end{parts}

\begin{parts}
\item Expand and simplify.

      \begin{subparts}
      \item $3(2x + 5) - 2(x - 1)$

      \AnswerLine[][]
      \Marks{2}

      \item $(x + 3)(x - 2)$

      \AnswerLine[][]
      \Marks{2}
      \end{subparts}

\item Factorise completely.

      \begin{subparts}
      \item $12x^2 + 18x$

      \AnswerLine[][]
      \Marks{1}

      \item $x^2 - 9$

      \AnswerLine[][]
      \Marks{1}

      \item $6x^2 + 7x - 3$

      \AnswerLine[][]
      \Marks{2}
      \end{subparts}

\item Solve.

      \begin{subparts}
      \item $3x + 7 = 19$

      \AnswerLine[][]
      \Marks{1}

      \item $5(x - 2) = 3(x + 1)$

      \AnswerLine[][]
      \Marks{2}
      \end{subparts}

\item Work out the value of

      \begin{subparts}
      \item $3^4$

      \AnswerLine[][]
      \Marks{1}
      \end{subparts}
\end{parts}

\begin{parts}
\item A box has length 12 cm, width 8 cm and height 5 cm.

      \begin{subparts}
      \item Calculate the volume of this box.
            Give the units of your answer.

      \AnswerLine[][]
      \Marks{3}
      \end{subparts}

\item These are the first four diagrams in a sequence.
      Each diagram is made from small equilateral triangles.

      Diagram 1    Diagram 2    Diagram 3    Diagram 4

      \begin{subparts}
      \item Write down the number of lines of symmetry of Diagram 3.

      \AnswerLine[][]
      \Marks{1}

      \item Complete the table.

            \begin{tabular}{|c|c|c|c|}
            \hline
            Diagram number (n) & 1 & 2 & 3 \\
            \hline
            Number of white triangles (w) & 1 & 3 & 6 \\
            \hline
            Number of grey triangles (g) & 0 &  & 3 \\
            \hline
            Total number of small triangles (t) & 1 & 4 &  \\
            \hline
            \end{tabular}

      \Marks{2}

      \item Find a formula, in terms of n, for the total number of small triangles, t, in Diagram n.

      t = \AnswerLine[]
      \Marks{1}

      \item The formula for the number of white triangles, w, in Diagram n is w = 12n(n + 1).

            Show that this formula gives the correct number of white triangles when n = 3.

      \Marks{2}

      \item Complete this statement for Diagram 15.

            When n = 15, w = \AnswerLine[], g = \AnswerLine[] and t = \AnswerLine[]
      \Marks{3}
      \end{subparts}
\end{parts}

